import React, { useState, useEffect } from 'react'
import TopNav from '../bars/TopNav'
import Footer from '../bars/Footer'
import plus from '../svg/Plus.svg'
import minus from '../svg/minus.svg'

function Faq() {
    useEffect(() => {
        window.scrollTo(0, 0);
      }, []);

    const [divStates, setDivStates] = useState({});

    const toggleDiv = (divId) => {
        setDivStates((prevState) => ({
            ...prevState,
            [divId]: !prevState[divId]
        }));
    };

    return (
        <div>
            <TopNav />
            <div className='top_section mt-[120px] mb-[73px]'>
                <h2 className='text-center lg:font-semibold font-medium'>FAQs</h2>
                <p className='w-full pt-8 md:w-[60%] text-center text-[#797979] mx-auto'>Have questions? We've got answers! Explore the frequently asked questions below to learn more about how Inaipi can transform your customer service experience.</p>
                <div className='flex flex-col space-y-10 mt-[56px]'>
                    <div className='flex flex-col'>
                        {/* <div onClick={() => toggleDiv('inaipi')} className="flex justify-between items-center cursor-pointer w-full pb-5" style={{ borderBottom: '1px solid var(--para, #797979)' }}>
                            <div className='faq'>What is Inaipi ?</div>
                            {divStates['inaipi'] ? (
                                <img src={minus} className='plus' />
                            ) : (
                                <img src={plus} className='plus' />
                            )}
                        </div> */}
                        <div className={`toggle-container ${divStates['inaipi'] ? 'visible' : 'hidden'}`}>
                            <div className="content">
                                <p className='p-5 leading-[35px]'>Inaipi is a UAE-based leading provider of a modern communication platform that offers superior customer experience solutions custom-built for the different needs of the market. We have helped over 500 global customers strengthen customer loyalty with solutions customized to their needs.</p>
                            </div>
                        </div>
                    </div>
                    <div className='flex flex-col'>
                        <div onClick={() => toggleDiv('contactCenter')} className="flex justify-between items-center cursor-pointer w-full pb-5" style={{ borderBottom: '1px solid var(--para, #797979)' }}>
                            <div className='faq'>What is Cloud Contact Center ?</div>
                            {divStates['contactCenter'] ? (
                                <img src={minus} className='plus' />
                            ) : (
                                <img src={plus} className='plus' />
                            )}
                        </div>
                        <div className={`toggle-container ${divStates['contactCenter'] ? 'visible' : 'hidden'}`}>
                            <div className="content">
                                <p className='p-5 leading-[35px]'>A cloud contact center is a customer service and support solution that is hosted and operated in the cloud, allowing businesses to manage and handle customer interactions, such as phone calls, emails, chats, and more, from anywhere with internet connectivity. It offers flexibility, scalability, and cost-effectiveness compared to traditional on-premises contact center systems.</p>
                            </div>
                        </div>
                    </div>
                    <div className='flex flex-col'>
                        <div onClick={() => toggleDiv('benefits')} className="flex justify-between items-center cursor-pointer w-full pb-5" style={{ borderBottom: '1px solid var(--para, #797979)' }}>
                            <div className='faq'>Cloud Contact Center Benefits ?</div>
                            {divStates['benefits'] ? (
                                <img src={minus} className='plus' />
                            ) : (
                                <img src={plus} className='plus' />
                            )}
                        </div>
                        <div className={`toggle-container ${divStates['benefits'] ? 'visible' : 'hidden'}`}>
                            <div className="content">
                                <p className='p-5 leading-[35px]'>Cost-efficiency, scalability, flexibility, remote accessibility, and the ability to access advanced features and analytics for enhanced customer service and support.</p>
                            </div>
                        </div>
                    </div>
                    <div className='flex flex-col'>
                        <div onClick={() => toggleDiv('digital')} className="flex justify-between items-center cursor-pointer w-full pb-5" style={{ borderBottom: '1px solid var(--para, #797979)' }}>
                            <div className='faq'>What is Digital Contact Center ?</div>
                            {divStates['digital'] ? (
                                <img src={minus} className='plus' />
                            ) : (
                                <img src={plus} className='plus' />
                            )}
                        </div>
                        <div className={`toggle-container ${divStates['digital'] ? 'visible' : 'hidden'}`}>
                            <div className="content">
                                <p className='p-5 leading-[35px]'>Customer service and support platform that uses digital channels like email, chat, social media, and messaging apps to engage with customers, providing a more versatile and convenient means of communication compared to traditional phone-based call centers.</p>
                            </div>
                        </div>
                    </div>
                    <div className='flex flex-col'>
                        <div onClick={() => toggleDiv('benefitChannel')} className="flex justify-between items-center cursor-pointer w-full pb-5" style={{ borderBottom: '1px solid var(--para, #797979)' }}>
                            <div className='faq'>Benefits of Digital Channels ?</div>
                            {divStates['benefitChannel'] ? (
                                <img src={minus} className='plus' />
                            ) : (
                                <img src={plus} className='plus' />
                            )}
                        </div>
                        <div className={`toggle-container ${divStates['benefitChannel'] ? 'visible' : 'hidden'}`}>
                            <div className="content">
                                <p className='p-5 leading-[35px]'>Faster communication, wider reach, cost-efficiency, convenience, and the ability to track and analyze customer interactions for improved service.</p>
                            </div>
                        </div>
                    </div>
                    <div className='flex flex-col'>
                        <div onClick={() => toggleDiv('cobrwosing')} className="flex justify-between items-center cursor-pointer w-full pb-5" style={{ borderBottom: '1px solid var(--para, #797979)' }}>
                            <div className='faq'>Benefits of Co-browsing ?</div>
                            {divStates['cobrwosing'] ? (
                                <img src={minus} className='plus' />
                            ) : (
                                <img src={plus} className='plus' />
                            )}
                        </div>
                        <div className={`toggle-container ${divStates['cobrwosing'] ? 'visible' : 'hidden'}`}>
                            <div className="content">
                                <p className='p-5 leading-[35px]'>Co-browsing is an invaluable tool for businesses and customer support. It allows for real-time visual collaboration between agents and customers, enhancing the overall experience.</p>
                            </div>
                        </div>
                    </div>
                    <div className='flex flex-col'>
                        <div onClick={() => toggleDiv('integrate')} className="flex justify-between items-center cursor-pointer w-full pb-5" style={{ borderBottom: '1px solid var(--para, #797979)' }}>
                            <div className='faq'>How Do I Migrate My Existing Contact Center To The Cloud?</div>
                            {divStates['integrate'] ? (
                                <img src={minus} className='plus' />
                            ) : (
                                <img src={plus} className='plus' />
                            )}
                        </div>
                        <div className={`toggle-container ${divStates['integrate'] ? 'visible' : 'hidden'}`}>
                            <div className="content">
                                <p className='p-5 leading-[35px]'>The migration process varies depending on your current setup and requirements. Generally, it involves assessing your needs, selecting a suitable cloud contact center provider, data migration, and training for your team. We offer you guidance and support throughout the migration process.</p>
                            </div>
                        </div>
                    </div>
                    <div className='flex flex-col'>
                        <div onClick={() => toggleDiv('price')} className="flex justify-between items-center cursor-pointer w-full pb-5" style={{ borderBottom: '1px solid var(--para, #797979)' }}>
                            <div className='faq'>Can I Integrate A Cloud Contact Center With My Existing CRM Or Other Business Systems?</div>
                            {divStates['price'] ? (
                                <img src={minus} className='plus' />
                            ) : (
                                <img src={plus} className='plus' />
                            )}
                        </div>
                        <div className={`toggle-container ${divStates['price'] ? 'visible' : 'hidden'}`}>
                            <div className="content">
                                <p className='p-5 leading-[35px]'>Yes, our solutions offer integration options with popular CRM platforms and other business applications to ensure a seamless flow of customer data and interaction history across systems.</p>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
            <Footer />
        </div>
    )
}

export default Faq
