import axios from "axios";
import React, { useEffect, useState } from 'react'
import DataTable from 'react-data-table-component'
import { CSVLink } from 'react-csv';
import Topbar from "../bars/TopNav";
import Footer from "../bars/Footer";

function Datatable() {

    const [data, setData] = useState([]);
    const [search, setSearch] = useState("");
    const [filteredData, setFilteredData] = useState([]);

    const getData = async () => {
        try {
            const response = await axios.get("https://1vdi4lgmfa.execute-api.us-east-1.amazonaws.com/get_every_details");
            setData(response.data);
            setFilteredData(response.data);
        } catch (error) {
            console.log(error);
        }
    };

    const columns = [
        {
            name: "First Name",
            selector: row => row.firstname,
            sortable: true,
        },
        {
            name: "Last Name",
            selector: row => row.lastname
        },
        {
            name: "Company",
            selector: row => row.company
        },
        {
            name: "Email",
            selector: row => row.email
        },
        {
            name: "Phone",
            selector: row => row.phone
        },
        {
            name: "Comments",
            selector: row => row.comments
        }


    ];

    const extractDataForExport = () => {
        return filteredData.map(row => ({
            "First Name": row.firstname,
            "Last Name": row.lastname,
            "Company": row.company,
            "Email": row.email,
            "Phone": row.phone,
            "Comments": row.comments
        }));
    };

    useEffect(() => {
        getData();
    }, []);

    useEffect(() => {
        const result = data.filter(row => {
            return Object.values(row).some(value =>
                value.toLowerCase().includes(search.toLowerCase())
            );
        });
        setFilteredData(result);
    }, [search]);



    return (
        <div>
            <Topbar />
            <div className='top_section flex flex-col items-center mt-[120px] mb-20'>
                <DataTable title="Contact us List"
                    columns={columns} data={filteredData} pagination fixedHeader fixedHeaderScrollHeight="450px" selectableRowsHighlight highlightOnHover
                    subHeader subHeaderComponent={
                        <div className="relative z-10 top-[-48px] flex space-x-2">
                            <CSVLink data={extractDataForExport()} filename="mydata.csv" className='flex space-x-1 items-center p-3 text-sm bg-[#006fff] text-white rounded-md px-4'>
                                <div>Export</div>
                                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="white" class="w-5 h-5">
                                    <path fill-rule="evenodd" d="M12 2.25a.75.75 0 01.75.75v11.69l3.22-3.22a.75.75 0 111.06 1.06l-4.5 4.5a.75.75 0 01-1.06 0l-4.5-4.5a.75.75 0 111.06-1.06l3.22 3.22V3a.75.75 0 01.75-.75zm-9 13.5a.75.75 0 01.75.75v2.25a1.5 1.5 0 001.5 1.5h13.5a1.5 1.5 0 001.5-1.5V16.5a.75.75 0 011.5 0v2.25a3 3 0 01-3 3H5.25a3 3 0 01-3-3V16.5a.75.75 0 01.75-.75z" clip-rule="evenodd" />
                                </svg>
                            </CSVLink>
                            <input type="text" placeholder="Search here" className="p-2 border border-1-gray-300 rounded-md shadow-sm outline-none"
                                value={search} onChange={(e) => setSearch(e.target.value)} />
                        </div>} />
            </div>
            <Footer />
        </div>
    )
}

export default Datatable
